var sensor = String(msg.topic || '').split('/').pop();
var units = { temperature: 'C', ph: 'pH', tds: 'ppm', do: 'mg/L', turbidity: 'NTU' };
var HISTORY_INTERVAL_MS = 2 * 60 * 1000;
if (!Object.prototype.hasOwnProperty.call(units, sensor)) return null;
var sensorSettings = flow.get('sensors') || {};
if (sensorSettings[sensor] && sensorSettings[sensor].enabled === false) return null;
var value = Number(msg.payload && msg.payload.value);
if (!Number.isFinite(value)) return null;
var now = Date.now();
var decimals = sensor === 'tds' ? 1 : 2;
var reading = { value: Number(value.toFixed(decimals)), unit: msg.payload.unit || units[sensor], status: msg.payload.status || 'normal', updatedAt: now };
var live = { rtdbPath: 'sensors/' + sensor, payload: reading };
var history = null;
if (now - (flow.get('lastHistory_' + sensor) || 0) >= HISTORY_INTERVAL_MS) {
  flow.set('lastHistory_' + sensor, now);
  history = { rtdbPath: 'history/sensors/' + sensor, payload: { value: reading.value, unit: reading.unit, status: reading.status, timestamp: now } };
}
return [[live], history ? [history] : [], [{ sensor: sensor, value: reading.value, timestamp: now }]];

var parts = String(msg.topic || '').split('/');
var id = parts[2];
var allowed = ['waterPump', 'aerator', 'heater', 'phPumpDown', 'phPumpUp', 'nutritionPump', 'buzzer'];
if (allowed.indexOf(id) === -1 || !msg.payload || typeof msg.payload.running !== 'boolean') return null;
return { rtdbPath: 'actuators/' + id, payload: { running: msg.payload.running, reportedAt: Date.now() } };

if (!msg.payload || typeof msg.payload !== 'object') return null;
var previous = flow.get('actuators') || {};
var current = msg.payload;
flow.set('actuators', current);
var commands = [];
Object.keys(current).forEach(function (id) {
  var actuator = current[id] || {};
  var rpc = actuator.command;
  var rpcKey = rpc && rpc.id ? String(rpc.id) : '';
  var isValidRpc = rpc && ['on', 'off'].indexOf(rpc.action) !== -1 && rpcKey;
  var lastRpcKey = flow.get('lastRpc_' + id) || '';
  if (isValidRpc && rpcKey !== lastRpcKey) {
    flow.set('lastRpc_' + id, rpcKey);
    commands.push({ payload: { device: id, action: rpc.action, source: rpc.source || 'web', timestamp: rpc.requestedAt || Date.now() } });
    return;
  }
  var wasEnabled = !previous[id] || previous[id].enabled !== false;
  var isDisabled = actuator.enabled === false;
  if (wasEnabled && isDisabled && !(isValidRpc && rpc.action === 'off')) {
    commands.push({ payload: { device: id, action: 'off', source: 'rtdb-disable', timestamp: Date.now() } });
  }
});
return [null, commands];

var rules = flow.get('actuators') || {};
var commands = [];
var cooldowns = {
  waterPump: 20000,
  aerator: 20000,
  heater: 20000,
  buzzer: 5000,
  phPumpDown: 30000,
  phPumpUp: 30000,
  nutritionPump: 30000
};
var now = msg.timestamp || Date.now();
Object.keys(rules).forEach(function (id) {
  var actuator = rules[id] || {};
  var rule = actuator.automation;
  if (!actuator.enabled || actuator.mode !== 'auto' || !rule || rule.sensor !== msg.sensor) return;
  var threshold = Number(rule.value);
  if (!Number.isFinite(threshold)) return;
  var h = Math.max(0, Number(rule.hysteresis) || 0);
  var triggered = false;
  if (rule.condition === 'below') triggered = msg.value <= threshold;
  if (rule.condition === 'above') triggered = msg.value >= threshold;
  if (!triggered) return;
  var cooldown = cooldowns[id] || 10000;
  var lastCommand = flow.get('lastAutoCommand_' + id) || 0;
  if (now - lastCommand < cooldown) return;
  flow.set('lastAutoCommand_' + id, now);
  commands.push({ payload: { device: id, action: 'on', source: 'auto-threshold', timestamp: now } });
});
return [commands];

var device = String(msg.topic || '').split('/')[2];
var action = String((msg.payload && msg.payload.action) || '').toLowerCase();
if (!device || ['on', 'off', 'enable', 'disable'].indexOf(action) === -1) return null;
if (action === 'enable') action = 'on';
if (action === 'disable') action = 'off';
var now = Date.now();
return [[{ rtdbPath: 'actuators/' + device, payload: { running: action === 'on', status: action, lastRun: now, updatedAt: now } }], [{ rtdbPath: 'history/actuators', payload: { device: device, action: action, source: 'web', timestamp: now } }]];

var command = msg.payload || {};
var allowed = ['waterPump', 'aerator', 'heater', 'phPumpDown', 'phPumpUp', 'nutritionPump', 'buzzer'];
if (allowed.indexOf(command.device) === -1) { node.warn('Unsupported actuator: ' + command.device); return null; }
var running = command.action === 'on';
var now = command.timestamp || Date.now();
var outbound = { topic: 'aquaponics/actuators/' + command.device + '/command', payload: JSON.stringify({ action: command.action }) };
var state = { rtdbPath: 'actuators/' + command.device, payload: { running: running, status: running ? 'on' : 'off', lastRun: now, updatedAt: now, command: null } };
var log = { rtdbPath: 'history/actuators', payload: { device: command.device, action: command.action, source: command.source || 'auto', timestamp: now } };
return [[outbound], [state], [log]];
